const { SQSClient, ReceiveMessageCommand, DeleteMessageCommand } = require("@aws-sdk/client-sqs");
const { Client } = require('pg'); // PostgreSQL client
require('dotenv').config();

const sqsClient = new SQSClient({ region: process.env.AWS_REGION });
const queueUrl = process.env.SQS_QUEUE_URL;

const dbClient = new Client({
  user: process.env.DB_USER,
  host: process.env.DB_HOST,
  database: process.env.DB_NAME,
  password: process.env.DB_PASSWORD,
  port: process.env.DB_PORT,
  ssl: {
    rejectUnauthorized: false
  }
});

async function processMessage(message) {
  const transaction = JSON.parse(message.Body);
  const query = 'UPDATE accounts SET balance = balance + $1 WHERE account_id = $2';
  const values = [transaction.amount, transaction.accountId];

  try {
    await dbClient.query(query, values);
    console.log(`Processed transaction for account ${transaction.accountId}`);
  } catch (err) {
    console.error('Error processing transaction:', err);
  }
}

async function receiveMessages() {
  const params = {
    QueueUrl: queueUrl,
    MaxNumberOfMessages: 10,
    WaitTimeSeconds: 20
  };

  try {
    const data = await sqsClient.send(new ReceiveMessageCommand(params));
    if (data.Messages) {
      for (const message of data.Messages) {
        await processMessage(message);
        await sqsClient.send(new DeleteMessageCommand({
          QueueUrl: queueUrl,
          ReceiptHandle: message.ReceiptHandle
        }));
      }
    }
  } catch (err) {
    console.error('Error receiving messages:', err);
  }
}

async function startConsumer() {
  try {
    await dbClient.connect();
    console.log('Connected to the database');
    setInterval(receiveMessages, 1000);
  } catch (err) {
    console.error('Error connecting to the database:', err);
  }
}

startConsumer();